module RefModule(  
    input [15:0] binary_image,  
    output reg [3:0] accumulator  
);  
    integer obf_i;  
    always @(*) begin  
        accumulator = 4'b0000;  
        for (obf_i = 0; obf_i < 16; obf_i = obf_i + 1) begin  
            if (binary_image[obf_i]) begin  
                accumulator = accumulator + 1;  
            end  
        end  
    end  
endmodule
